import type { ColumnDef, RowData } from '@tanstack/table-core';
import RowSelectCell from './cells/row-select-cell.svelte';
import RowSelectHeader from './cells/row-select-header.svelte';
import { renderComponent } from '$lib/table';
import type { DataGridSelectHitboxSize } from '$lib/types/data-grid.js';

export interface GetDataGridSelectColumnOptions<TData extends RowData> extends Omit<
	Partial<ColumnDef<TData, unknown>>,
	'id' | 'header' | 'cell' | 'meta'
> {
	enableRowMarkers?: boolean;
	readOnly?: boolean;
	hitboxSize?: DataGridSelectHitboxSize;
	debug?: boolean;
	meta?: ColumnDef<TData, unknown>['meta'];
}

export function getDataGridSelectColumn<TData extends RowData>(
	options: GetDataGridSelectColumnOptions<TData> = {}
): ColumnDef<TData, unknown> {
	const {
		size = 40,
		enableHiding = false,
		enableResizing = false,
		enableSorting = false,
		enableRowMarkers = false,
		readOnly = false,
		hitboxSize = 'default',
		debug = false,
		meta,
		...props
	} = options;

	return {
		id: 'select',
		header: ({ table }) =>
			renderComponent(RowSelectHeader, {
				table,
				hitboxSize,
				readOnly,
				debug
			}),
		cell: ({ row, table }) =>
			renderComponent(RowSelectCell, {
				row,
				table,
				rowIndex: row.index,
				enableRowMarkers,
				readOnly,
				hitboxSize,
				debug
			}),
		size,
		enableHiding,
		enableResizing,
		enableSorting,
		meta: {
			...meta,
			label: meta?.label ?? 'Select',
			cell: {
				variant: 'row-select',
				enableRowMarkers,
				readOnly,
				hitboxSize,
				debug
			}
		},
		...props
	};
}

// Data Grid Types for TableCN-Svelte

import type { ColumnDef, Table, Row, Cell, Column, RowData, Updater } from '@tanstack/table-core';
import type { SvelteSet, SvelteMap } from 'svelte/reactivity';
import type { Snippet, Component } from 'svelte';

// ============================================
// Base Types
// ============================================

export type Direction = 'ltr' | 'rtl';

export interface Option {
	label: string;
	value: string;
}

export type RowHeightValue = 'short' | 'medium' | 'tall' | 'extra-tall';

export type DataGridSelectHitboxSize = 'default' | 'sm' | 'lg';

export interface CellSelectOption {
	label: string;
	value: string;
	icon?: Component;
	count?: number;
}

// ============================================
// Cell Types
// ============================================

export type CellOpts =
	| { variant: 'short-text' }
	| { variant: 'long-text' }
	| { variant: 'number'; min?: number; max?: number; step?: number }
	| { variant: 'select'; options: CellSelectOption[] }
	| { variant: 'multi-select'; options: CellSelectOption[] }
	| { variant: 'checkbox' }
	| { variant: 'date' }
	| { variant: 'url' }
	| {
			variant: 'row-select';
			enableRowMarkers?: boolean;
			readOnly?: boolean;
			hitboxSize?: DataGridSelectHitboxSize;
			debug?: boolean;
	  }
	| {
			variant: 'file';
			maxFileSize?: number;
			maxFiles?: number;
			accept?: string;
			multiple?: boolean;
	  };

export interface UpdateCell {
	rowIndex: number;
	columnId: string;
	value: unknown;
}

// ============================================
// Position & Selection Types
// ============================================

export interface CellPosition {
	rowIndex: number;
	columnId: string;
	/** Resolve display index after sort/filter; preferred over rowIndex when adding rows */
	rowId?: string;
}

export interface CellRange {
	start: CellPosition;
	end: CellPosition;
}

export interface SelectionState {
	selectedCells: Set<string>;
	selectionRange: CellRange | null;
	isSelecting: boolean;
}

// ============================================
// Context Menu Types
// ============================================

export interface ContextMenuState {
	open: boolean;
	x: number;
	y: number;
}

// ============================================
// Paste Dialog Types
// ============================================

export interface PasteDialogState {
	open: boolean;
	rowsNeeded: number;
	clipboardText: string;
}

// ============================================
// Navigation Types
// ============================================

export type NavigationDirection =
	| 'up'
	| 'down'
	| 'left'
	| 'right'
	| 'home'
	| 'end'
	| 'ctrl+up'
	| 'ctrl+down'
	| 'ctrl+home'
	| 'ctrl+end'
	| 'pageup'
	| 'pagedown'
	| 'pageleft'
	| 'pageright';

// ============================================
// Search Types
// ============================================

// Type alias for search match - same as CellPosition
export type SearchMatch = CellPosition;

// Data-only search state (used by stores)
export interface SearchStateData {
	searchOpen: boolean;
	searchQuery: string;
	searchMatches: SearchMatch[];
	matchIndex: number;
}

// Full search state with callbacks (used by components)
export interface SearchState extends SearchStateData {
	onSearchOpenChange: (open: boolean) => void;
	onSearchQueryChange: (query: string) => void;
	onSearch: (query: string) => void;
	onNavigateToNextMatch: () => void;
	onNavigateToPrevMatch: () => void;
}

// ============================================
// Cell Variant Props
// ============================================

export interface CellVariantProps<TData> {
	cell: Cell<TData, unknown>;
	table: Table<TData>;
	rowIndex: number;
	columnId: string;
	isEditing: boolean;
	isFocused: boolean;
	isSelected: boolean;
	readOnly?: boolean;
	/** Centralized cell value with fine-grained reactivity from SvelteMap */
	cellValue: unknown;
}

// ============================================
// File Cell Types
// ============================================

export interface FileCellData {
	id: string;
	name: string;
	size: number;
	type: string;
	url?: string;
}

// ============================================
// Filter Types
// ============================================

export type TextFilterOperator =
	| 'contains'
	| 'notContains'
	| 'equals'
	| 'notEquals'
	| 'startsWith'
	| 'endsWith'
	| 'isEmpty'
	| 'isNotEmpty';

export type NumberFilterOperator =
	| 'equals'
	| 'notEquals'
	| 'lessThan'
	| 'lessThanOrEqual'
	| 'greaterThan'
	| 'greaterThanOrEqual'
	| 'isBetween'
	| 'isEmpty'
	| 'isNotEmpty';

export type DateFilterOperator =
	| 'equals'
	| 'notEquals'
	| 'before'
	| 'after'
	| 'onOrBefore'
	| 'onOrAfter'
	| 'isBetween'
	| 'isEmpty'
	| 'isNotEmpty';

export type SelectFilterOperator =
	| 'is'
	| 'isNot'
	| 'isAnyOf'
	| 'isNoneOf'
	| 'isEmpty'
	| 'isNotEmpty';

export type BooleanFilterOperator = 'isTrue' | 'isFalse';

export type FilterOperator =
	| TextFilterOperator
	| NumberFilterOperator
	| DateFilterOperator
	| SelectFilterOperator
	| BooleanFilterOperator;

export interface FilterValue {
	operator: FilterOperator;
	value?: string | number | string[];
	endValue?: string | number;
}

// ============================================
// TanStack Table Meta Extension
// ============================================

declare module '@tanstack/table-core' {
	// eslint-disable-next-line @typescript-eslint/no-unused-vars
	interface ColumnMeta<TData extends RowData, TValue> {
		label?: string;
		cell?: CellOpts;
	}

	interface TableMeta<TData extends RowData> {
		dataGridRef?: HTMLElement | null;
		cellMapRef?: Map<string, HTMLDivElement>;
		focusedCell?: CellPosition | null;
		editingCell?: CellPosition | null;
		selectionState?: SelectionState;
		searchOpen?: boolean;
		readOnly?: boolean;
		getIsCellSelected?: (rowIndex: number, columnId: string) => boolean;
		// SvelteMap for fine-grained cell value reactivity - cells access map.get(key) in $derived
		cellValueMap?: SvelteMap<string, unknown>;
		// SvelteSet for fine-grained cell selection reactivity
		selectedCellsSet?: SvelteSet<string>;
		// Version counter to force cell re-renders when selection changes
		selectionVersion?: number;
		getIsSearchMatch?: (rowIndex: number, columnId: string) => boolean;
		getIsActiveSearchMatch?: (rowIndex: number, columnId: string) => boolean;
		// SvelteSet for fine-grained reactive search match lookups
		searchMatchSet?: SvelteSet<string>;
		activeSearchMatch?: CellPosition | null;
		rowHeight?: RowHeightValue;
		onRowHeightChange?: (updater: Updater<RowHeightValue>) => void;
		getVisualRowIndex?: (rowId: string) => number | undefined;
		onRowSelect?: (rowId: string, checked: boolean, shiftKey: boolean) => void;
		onDataUpdate?: (params: UpdateCell | UpdateCell[]) => void;
		onRowsDelete?: (rowIndices: number[]) => void | Promise<void>;
		onColumnClick?: (columnId: string) => void;
		onCellClick?: (rowIndex: number, columnId: string, event?: MouseEvent) => void;
		onCellDoubleClick?: (rowIndex: number, columnId: string) => void;
		onCellMouseDown?: (rowIndex: number, columnId: string, event: MouseEvent) => void;
		onCellMouseEnter?: (rowIndex: number, columnId: string, event: MouseEvent) => void;
		onCellMouseUp?: () => void;
		onCellContextMenu?: (rowIndex: number, columnId: string, event: MouseEvent) => void;
		onCellEditingStart?: (rowIndex: number, columnId: string) => void;
		onCellEditingStop?: (opts?: {
			direction?: NavigationDirection;
			moveToNextRow?: boolean;
		}) => void;
		onCellsCopy?: () => void | Promise<void>;
		onCellsCut?: () => void | Promise<void>;
		onCellsPaste?: (expand?: boolean) => void | Promise<void>;
		onFilesUpload?: (params: {
			files: File[];
			rowIndex: number;
			columnId: string;
			row: TData;
		}) => Promise<FileCellData[]>;
		onFilesDelete?: (params: {
			fileIds: string[];
			rowIndex: number;
			columnId: string;
			row: TData;
		}) => void | Promise<void>;
		contextMenu?: ContextMenuState;
		onContextMenuOpenChange?: (open: boolean) => void;
		pasteDialog?: PasteDialogState;
		onPasteDialogOpenChange?: (open: boolean) => void;
		/** @deprecated Use onCellsPaste(true) instead. */
		onPasteWithExpansion?: () => void;
		/** @deprecated Use onCellsPaste(false) instead. */
		onPasteWithoutExpansion?: () => void;
		onSelectionClear?: () => void;
	}
}

// ============================================
// Row Height Constants
// ============================================

export const ROW_HEIGHT_VALUES: Record<RowHeightValue, number> = {
	short: 36,
	medium: 56,
	tall: 76,
	'extra-tall': 96
};

export const ROW_LINE_COUNTS: Record<RowHeightValue, number> = {
	short: 1,
	medium: 2,
	tall: 3,
	'extra-tall': 4
};

// ============================================
// Component Props Types
// ============================================

export interface DataGridProps<TData> {
	data: TData[];
	columns: ColumnDef<TData, unknown>[];
	readOnly?: boolean;
	height?: number;
	rowHeight?: RowHeightValue;
	autoFocus?: boolean | { rowIndex?: number; columnId?: string };
	enableColumnSelection?: boolean;
	enableSingleCellSelection?: boolean;
	enableSearch?: boolean;
	enablePaste?: boolean;
	overscan?: number;
	class?: string;

	// Callbacks
	onDataChange?: (data: TData[]) => void;
	onRowAdd?: (
		event?: MouseEvent
	) => Partial<CellPosition> | null | void | Promise<Partial<CellPosition> | null | void>;
	onRowsAdd?: (count: number) => void | Promise<void>;
	onRowsDelete?: (rows: TData[], rowIndices: number[]) => void | Promise<void>;
	onPaste?: (updates: UpdateCell[]) => void | Promise<void>;
	onFilesUpload?: (params: {
		files: File[];
		rowIndex: number;
		columnId: string;
		row: TData;
	}) => Promise<FileCellData[]>;
	onFilesDelete?: (params: {
		fileIds: string[];
		rowIndex: number;
		columnId: string;
		row: TData;
	}) => void | Promise<void>;

	// Snippets for customization
	header?: Snippet<[{ column: Column<TData, unknown> }]>;
	cell?: Snippet<[{ cell: Cell<TData, unknown>; row: Row<TData> }]>;
	empty?: Snippet;
	footer?: Snippet;
}

// ============================================
// Utility Functions
// ============================================

/**
 * Creates a unique cell key from row index and column id
 */
export function getCellKey(rowIndex: number, columnId: string): string {
	return `${rowIndex}:${columnId}`;
}

/** Stable cache key for edited values — survives sort/filter. */
export function getCellValueKey(rowId: string, columnId: string): string {
	return `${rowId}\0${columnId}`;
}

/**
 * Parses a cell key back into row index and column id
 */
export function parseCellKey(cellKey: string): CellPosition {
	const parts = cellKey.split(':');
	const rowIndexStr = parts[0];
	const columnId = parts[1];
	if (rowIndexStr && columnId) {
		const rowIndex = parseInt(rowIndexStr, 10);
		if (!Number.isNaN(rowIndex)) {
			return { rowIndex, columnId };
		}
	}
	return { rowIndex: 0, columnId: '' };
}

/**
 * Gets the pixel height for a row height value
 */
export function getRowHeightValue(rowHeight: RowHeightValue): number {
	return ROW_HEIGHT_VALUES[rowHeight];
}

/**
 * Gets the line count for a row height value
 */
export function getLineCount(rowHeight: RowHeightValue): number {
	return ROW_LINE_COUNTS[rowHeight];
}

/**
 * Gets common pinning styles for a column (port of TableCN's getCommonPinningStyles)
 */
export function getCommonPinningStyles<TData>(params: {
	column?: Column<TData, unknown>;
	withBorder?: boolean;
}): Record<string, string | number | undefined> {
	const { column, withBorder = false } = params;

	// Return default styles if column is undefined
	if (!column) {
		return {
			position: 'relative',
			background: 'var(--background)',
			zIndex: undefined
		};
	}

	// Wrap in try-catch to handle SSR edge cases where TanStack internal state may not be ready
	try {
		const isPinned = column.getIsPinned();
		const isLastLeftPinnedColumn = isPinned === 'left' && column.getIsLastColumn('left');
		const isFirstRightPinnedColumn = isPinned === 'right' && column.getIsFirstColumn('right');

		return {
			boxShadow: withBorder
				? isLastLeftPinnedColumn
					? '-4px 0 4px -4px var(--border) inset'
					: isFirstRightPinnedColumn
						? '4px 0 4px -4px var(--border) inset'
						: undefined
				: undefined,
			left: isPinned === 'left' ? `${column.getStart('left')}px` : undefined,
			right: isPinned === 'right' ? `${column.getAfter('right')}px` : undefined,
			opacity: isPinned ? 0.97 : 1,
			position: isPinned ? 'sticky' : 'relative',
			background: isPinned ? 'var(--background)' : 'var(--background)',
			width: column.getSize(),
			zIndex: isPinned ? 1 : undefined
		};
	} catch {
		// Return default styles if column methods fail (e.g., during SSR)
		return {
			position: 'relative',
			background: 'var(--background)',
			zIndex: undefined
		};
	}
}

import {
	type RowData,
	type Table,
	type TableOptions,
	type TableOptionsResolved,
	type TableState,
	createTable
} from '@tanstack/table-core';
import { createSubscriber } from 'svelte/reactivity';

/**
 * Bridges TanStack Table (external reactive system) to Svelte 5.
 *
 * 1. `$effect.pre` syncs options when parent `$state` changes (not on every table read).
 * 2. `createSubscriber` on proxy reads re-runs `$derived` when the table updates.
 * 3. Wrapped change handlers are stable references so `setOptions` does not retrigger callbacks.
 *
 * @see docs/REACTIVITY.md
 */
export function createSvelteTable<TData extends RowData>(
	options: TableOptions<TData>
): Table<TData> {
	let state: Partial<TableState> = {};

	const resolvedOptions: TableOptionsResolved<TData> = mergeObjects(
		{
			state: {},
			onStateChange() {},
			renderFallbackValue: null,
			mergeOptions: (defaultOptions: TableOptions<TData>, opts: Partial<TableOptions<TData>>) => {
				return mergeObjects(defaultOptions, opts);
			}
		},
		options
	);

	const table = createTable(resolvedOptions);
	state = table.initialState;

	let notifyTableUpdate: (() => void) | null = null;
	let lastDataRef: TData[] | null = null;
	let lastColumnsRef: TableOptions<TData>['columns'] | null = null;
	let lastStateKey = '';

	const subscribe = createSubscriber((update) => {
		notifyTableUpdate = update;
		return () => {
			notifyTableUpdate = null;
		};
	});

	function wrapControlledChange<Updater>(
		handler: ((updater: Updater) => void) | undefined
	): (updater: Updater) => void {
		return (updater) => {
			handler?.(updater);
			// Notify subscribers immediately; $effect.pre syncs options before paint.
			notifyTableUpdate?.();
		};
	}

	// Stable handler refs — recreated wrappers on every setOptions caused churn/loops.
	const onColumnFiltersChange = wrapControlledChange(options.onColumnFiltersChange);
	const onSortingChange = wrapControlledChange(options.onSortingChange);
	const onPaginationChange = wrapControlledChange(options.onPaginationChange);
	const onColumnVisibilityChange = wrapControlledChange(options.onColumnVisibilityChange);
	const onRowSelectionChange = wrapControlledChange(options.onRowSelectionChange);
	const onStateChange: NonNullable<TableOptions<TData>['onStateChange']> = (updater) => {
		if (updater instanceof Function) {
			state = updater(state as TableState);
		} else {
			state = mergeObjects(state, updater);
		}

		notifyTableUpdate?.();
		options.onStateChange?.(updater);
	};

	function readReactiveData(): TData[] {
		const data = options.data as TData[] | (() => TData[]);
		return typeof data === 'function' ? data() : data;
	}

	function readReactiveState(): Partial<TableState> | undefined {
		const tableState = options.state;
		if (tableState === undefined) return undefined;
		return typeof tableState === 'function'
			? (tableState as () => Partial<TableState>)()
			: tableState;
	}

	function syncOptions() {
		table.setOptions((prev) => {
			return mergeObjects(prev, options, {
				state: mergeObjects(state, readReactiveState() ?? {}),
				onColumnFiltersChange,
				onSortingChange,
				onPaginationChange,
				onColumnVisibilityChange,
				onRowSelectionChange,
				onStateChange
			});
		});
	}

	$effect.pre(() => {
		const data = readReactiveData();
		const columns = options.columns;
		const stateKey = JSON.stringify({
			manualFiltering: options.manualFiltering,
			manualPagination: options.manualPagination,
			manualSorting: options.manualSorting,
			pageCount: options.pageCount,
			state: readReactiveState()
		});

		if (data === lastDataRef && columns === lastColumnsRef && stateKey === lastStateKey) return;
		lastDataRef = data;
		lastColumnsRef = columns;
		lastStateKey = stateKey;

		syncOptions();
		notifyTableUpdate?.();
	});

	return new Proxy(table, {
		get(target, prop, receiver) {
			subscribe();

			const value = Reflect.get(target, prop, receiver);

			if (typeof value === 'function') {
				return value.bind(target);
			}

			return value;
		}
	});
}

type MaybeThunk<T extends object> = T | (() => T | null | undefined);
type Intersection<T extends readonly unknown[]> = (T extends [infer H, ...infer R]
	? H & Intersection<R>
	: unknown) & {};

/**
 * Lazily merges several objects (or thunks) while preserving
 * getter semantics from every source.
 *
 * Proxy-based to avoid known WebKit recursion issue.
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function mergeObjects<Sources extends readonly MaybeThunk<any>[]>(
	...sources: Sources
): Intersection<{ [K in keyof Sources]: Sources[K] }> {
	const resolve = <T extends object>(src: MaybeThunk<T>): T | undefined =>
		typeof src === 'function' ? (src() ?? undefined) : src;

	const findSourceWithKey = (key: PropertyKey) => {
		for (let i = sources.length - 1; i >= 0; i--) {
			const obj = resolve(sources[i]);
			if (obj && key in obj) return obj;
		}
		return undefined;
	};

	return new Proxy(Object.create(null), {
		get(_, key) {
			const src = findSourceWithKey(key);

			return src?.[key as never];
		},

		has(_, key) {
			return !!findSourceWithKey(key);
		},

		ownKeys(): (string | symbol)[] {
			// eslint-disable-next-line svelte/prefer-svelte-reactivity
			const all = new Set<string | symbol>();
			for (const s of sources) {
				const obj = resolve(s);
				if (obj) {
					for (const k of Reflect.ownKeys(obj) as (string | symbol)[]) {
						all.add(k);
					}
				}
			}
			return [...all];
		},

		getOwnPropertyDescriptor(_, key) {
			const src = findSourceWithKey(key);
			if (!src) return undefined;
			return {
				configurable: true,
				enumerable: true,
				// eslint-disable-next-line @typescript-eslint/no-explicit-any
				value: (src as any)[key],
				writable: true
			};
		}
	}) as Intersection<{ [K in keyof Sources]: Sources[K] }>;
}

import type { Component, ComponentProps, Snippet } from "svelte";

/**
 * A helper class to make it easy to identify Svelte components in
 * `columnDef.cell` and `columnDef.header` properties.
 *
 * > NOTE: This class should only be used internally by the adapter. If you're
 * reading this and you don't know what this is for, you probably don't need it.
 *
 * @example
 * ```svelte
 * {@const result = content(context as any)}
 * {#if result instanceof RenderComponentConfig}
 *   {@const { component: Component, props } = result}
 *   <Component {...props} />
 * {/if}
 * ```
 */
export class RenderComponentConfig<TComponent extends Component> {
	component: TComponent;
	props: ComponentProps<TComponent> | Record<string, never>;
	constructor(
		component: TComponent,
		props: ComponentProps<TComponent> | Record<string, never> = {}
	) {
		this.component = component;
		this.props = props;
	}
}

/**
 * A helper class to make it easy to identify Svelte Snippets in `columnDef.cell` and `columnDef.header` properties.
 *
 * > NOTE: This class should only be used internally by the adapter. If you're
 * reading this and you don't know what this is for, you probably don't need it.
 *
 * @example
 * ```svelte
 * {@const result = content(context as any)}
 * {#if result instanceof RenderSnippetConfig}
 *   {@const { snippet, params } = result}
 *   {@render snippet(params)}
 * {/if}
 * ```
 */
export class RenderSnippetConfig<TProps> {
	snippet: Snippet<[TProps]>;
	params: TProps;
	constructor(snippet: Snippet<[TProps]>, params: TProps) {
		this.snippet = snippet;
		this.params = params;
	}
}

/**
 * A helper function to help create cells from Svelte components through ColumnDef's `cell` and `header` properties.
 *
 * This is only to be used with Svelte Components - use `renderSnippet` for Svelte Snippets.
 *
 * @param component A Svelte component
 * @param props The props to pass to `component`
 * @returns A `RenderComponentConfig` object that helps svelte-table know how to render the header/cell component.
 * @example
 * ```ts
 * // +page.svelte
 * const defaultColumns = [
 *   columnHelper.accessor('name', {
 *     header: header => renderComponent(SortHeader, { label: 'Name', header }),
 *   }),
 *   columnHelper.accessor('state', {
 *     header: header => renderComponent(SortHeader, { label: 'State', header }),
 *   }),
 * ]
 * ```
 * @see {@link https://tanstack.com/table/latest/docs/guide/column-defs}
 */
export function renderComponent<
	// eslint-disable-next-line @typescript-eslint/no-explicit-any
	T extends Component<any>,
	Props extends ComponentProps<T>,
>(component: T, props: Props = {} as Props) {
	return new RenderComponentConfig(component, props);
}

/**
 * A helper function to help create cells from Svelte Snippets through ColumnDef's `cell` and `header` properties.
 *
 * The snippet must only take one parameter.
 *
 * This is only to be used with Snippets - use `renderComponent` for Svelte Components.
 *
 * @param snippet
 * @param params
 * @returns - A `RenderSnippetConfig` object that helps svelte-table know how to render the header/cell snippet.
 * @example
 * ```ts
 * // +page.svelte
 * const defaultColumns = [
 *   columnHelper.accessor('name', {
